class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next
def cycle_start_node(head):
    slow = fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow is fast:
            break
    else:
        return None
    slow = head
    while slow is not fast:
        slow = slow.next
        fast = fast.next
    return slow

